var e=[{id:`L2_1`,type:`dialog`,speaker:`SOLDIER_NPC_NANAHARA_NULL`,text:{KOREA:`1차 방어선이 뚫렸습니다! 넘어옵니다!`,JPN:`第1次防御線が突破されました！　越えてきます！`,ENG:`1st defense line breached! They're coming your way!`,TWN:`突破第一道防線！它們正衝過來！`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SOLDIER_NPC_NANAHARA_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`SANAE_NANA_NULL_NULL`,text:{KOREA:`아카마 당주님. 맡기겠습니다.`,JPN:`赤間当主。お任せします。`,ENG:`Head of Akama, I leave this to you.`,TWN:`赤間堂主，交給你了。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SANAE_NANA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`ELDER_NPC_NANAHARA_OWL`,text:{KOREA:`디코이는 준비할 시간이 없어서 말입죠.`,JPN:`デコイは準備する時間がないっすよ。`,ENG:`We do not have enough time to prepare the decoys.`,TWN:`沒時間挖陷阱，`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SANAE_NANA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`ELDER_NPC_NANAHARA_OWL`,text:{KOREA:`화끈하게 화력지뢰로 가겠슴다!`,JPN:`気前よく火力地雷と行くっす！`,ENG:`So we'll blow them up with blazemines!`,TWN:`全都衝向地雷吧！`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SANAE_NANA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}}];export{e as default};